#include <stdio.h>
#include <stdlib.h>
int cmp(const void *a, const void *b){return (*(int*)a)-(*(int*)b);} 
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *A = (int*)malloc(N*sizeof(int));
        int *B = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d",&A[i]);
        for(int i=0;i<N;i++) scanf("%d",&B[i]);
        qsort(A,N,sizeof(int),cmp);
        int common=0;
        for(int i=0;i<N;i++){
            // binary search B[i] in A
            int l=0,r=N-1,mid,found=0;
            while(l<=r){
                mid=(l+r)/2;
                if(A[mid]==B[i]){found=1;break;}
                else if(A[mid]<B[i]) l=mid+1; else r=mid-1;
            }
            if(found) common++;
        }
        printf("%d\n",common);
        free(A); free(B);
    }
    return 0;
}

