    while(T--){
        int N; cin>>N;
        unordered_set<int> s; s.reserve(N*2);
        for(int i=0;i<N;i++){int x;cin>>x; s.insert(x);}        
        int common=0;
        for(int i=0;i<N;i++){
            int x;cin>>x;
            if(s.find(x)!=s.end()) common++;
        }
        cout<<common<<"\n";
    }
    return 0;
}

