import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        A = {int(next(it)) for _ in range(N)}
        common = 0
        for _ in range(N):
            if int(next(it)) in A:
                common += 1
        out_lines.append(str(common))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

